function replaceFocusIdReferences(oldId,newId){
  const escaped=oldId.replace(/[.*+?^${}()|[\]\\]/g,'\\$&');
  const rx=new RegExp(`(?<![A-Za-z0-9_])${escaped}(?![A-Za-z0-9_])`,'g');
  const walk=value=>{
    if(typeof value==='string')return value.replace(rx,newId);
    if(Array.isArray(value))return value.map(walk);
    if(value&&typeof value==='object')for(const key of Object.keys(value))value[key]=walk(value[key]);
    return value;
  };
  walk(project);
}
