sp.ownership??='project';sp.dependencyRequirements??=[];sp.allowedConditions??='always = yes';sp.visibleConditions??='';sp.removalCost??=-1;sp.targetedModifiers??='';sp.equipmentBonuses??='';sp.researchBonuses??='';$('#deleteSpirit').insertAdjacentHTML('beforebegin',`<div class="ownership-card"><strong>${escapeHtml(sp.ownership)} spirit</strong><small>Source: ${escapeHtml(sp.sourceName||'Current project')} · File: ${escapeHtml(sp.sourceFile||'project')} · Dependencies: ${escapeHtml((sp.dependencyRequirements||[]).join(', ')||'none')} · Conflict: ${sp.sourceConflict?'yes':'no'}${sp.upgradeFrom?' · Upgrades: '+escapeHtml(sp.upgradeFrom):''}</small></div><div class="row"><label>Removal cost<input id="spRemovalCost" type="number"></label><label>Picture key<input id="spPicture"></label></div><label>Allowed conditions<textarea id="spAllowed"></textarea></label><label>Visible conditions<textarea id="spVisible"></textarea></label><label>Targeted modifiers<textarea id="spTargeted"></textarea></label><label>Equipment bonuses<textarea id="spEquipment"></textarea></label><label>Research bonuses<textarea id="spResearch"></textarea></label><label>Dependency requirements (comma-separated)<input id="spDependencies"></label><details><summary>Preserved imported source script</summary><textarea readonly>${escapeHtml(sp.preservedSourceScript||sp.sourceRaw||'')}</textarea></details>`);
