$('#downloadUpdate').onclick=async()=>{if(!confirm('Download the newest Windows update from the public GitHub Release? This does not install it.'))return;$('#updateStatus').textContent='Downloading and verifying SHA-256 checksum…';const result=await api('/api/update/download',{});if(result.error){$('#updateStatus').textContent='Download failed: '+result.error;return}downloadedUpdatePath=result.path;$('#updateStatus').textContent=`Update downloaded and verified (${result.sha256.slice(0,12)}…).`;$('#installUpdate').disabled=false};
$('#installUpdate').onclick=async()=>{if(!downloadedUpdatePath)return;if(!confirm('Install the verified update now? Studio will close, replace only program files, and reopen. Projects, exports, backups, paths, and settings will be preserved.'))return;const result=await api('/api/update/install',{path:downloadedUpdatePath});$('#updateStatus').textContent=result.error||result.message};
$('#manualUpdate').onclick=async()=>{const selected=await api('/api/update/select-zip',{});if(selected.error)return $('#updateStatus').textContent=selected.error;if(!selected.path)return;if(!confirm('Verify and install this update ZIP using its adjacent .sha256 checksum file? Studio will close and reopen if verification succeeds.'))return;downloadedUpdatePath=selected.path;const result=await api('/api/update/install',{path:selected.path});$('#updateStatus').textContent=result.error||result.message};
const LOCAL_EXPORT_PATH='hoi4FocusStudio.exportPath',LOCAL_INSTALL_PATH='hoi4FocusStudio.installPath';
function openBaseRecovery(message){$('#baseRecoveryMessage').textContent=message||'This project needs its complete old mod source before it can export or install.';$('#baseRecoveryStatus').textContent='';$('#baseRecoveryDialog').showModal()}
async function recoverBase(kind){const selected=await api(`/api/base-source/select-${kind}`,{});if(selected.error)return $('#baseRecoveryStatus').textContent=selected.error;if(!selected.path)return;$('#baseRecoveryStatus').textContent='Validating and copying the selected source…';const result=await api('/api/base-source/recover',{path:selected.path});if(result.error)return $('#baseRecoveryStatus').textContent='Recovery failed: '+result.error;$('#baseRecoveryStatus').textContent=`Recovered and protected ${result.files} files. The original folder or ZIP is no longer required.`;setTimeout(()=>$('#baseRecoveryDialog').close(),900)}
$('#closeBaseRecovery').onclick=()=>$('#baseRecoveryDialog').close();$('#recoverBaseFolder').onclick=()=>recoverBase('folder');$('#recoverBaseZip').onclick=()=>recoverBase('zip');
$('#exportPath').value=localStorage.getItem(LOCAL_EXPORT_PATH)||'';$('#installPath').value=localStorage.getItem(LOCAL_INSTALL_PATH)||'';
function localPath(input,key){const value=input.value.trim();if(value)localStorage.setItem(key,value);else localStorage.removeItem(key);return value}
async function choosePath(input,key,title){const result=await api('/api/select-folder',{title});if(result.error)return showMessage(result.error);if(result.path){input.value=result.path;localStorage.setItem(key,result.path)}}
$('#chooseExportPath').onclick=()=>choosePath($('#exportPath'),LOCAL_EXPORT_PATH,'Choose export destination');
$('#chooseInstallPath').onclick=()=>choosePath($('#installPath'),LOCAL_INSTALL_PATH,'Choose Hearts of Iron IV mod folder');
$('#exportPath').onchange=()=>localPath($('#exportPath'),LOCAL_EXPORT_PATH);$('#installPath').onchange=()=>localPath($('#installPath'),LOCAL_INSTALL_PATH);
$('#save').onclick=()=>saveProjectNow(false);
$('#export').onclick=async()=>{const errors=validate();if(errors.length)return showMessage('Export blocked until these problems are fixed:\n\n'+errors.join('\n'));const exportPath=localPath($('#exportPath'),LOCAL_EXPORT_PATH);if(!exportPath)return showMessage('Choose an export destination first.');status.textContent='Exporting…';project.openExportFolder=$('#openExportFolder')?.checked!==false;project.exportVersion=$('#exportVersion')?.value||project.exportVersion||'v0_80';project.versionBump=$('#versionBump')?.value||'minor';const r=await api('/api/export',{...project,exportPath});if(r.recoveryRequired){status.textContent='Base-source recovery required';return openBaseRecovery(r.error)}if(!r.error&&r.version){project.exportVersion=r.version;$('#exportVersion').value=r.version;updateExportPreview();await saveProjectNow(true)}showMessage(r.error||`Export created:\n${r.zipPath||r.path}\n\nVersion: ${r.version}${r.opened?'\n\nThe folder was opened in File Explorer.':''}`);status.textContent=r.error?'Export failed':`Export complete · ${r.version}`};
$('#install').onclick=async()=>{const errors=validate();if(errors.length)return showMessage('Install blocked until these problems are fixed:\n\n'+errors.join('\n'));const hoi4ModFolder=localPath($('#installPath'),LOCAL_INSTALL_PATH);if(!hoi4ModFolder)return showMessage('Choose the Hearts of Iron IV mod folder first.');status.textContent='Installing test build…';const r=await api('/api/install',{...project,hoi4ModFolder});if(r.recoveryRequired){status.textContent='Base-source recovery required';return openBaseRecovery(r.error)}showMessage(r.error||`Test mod installed at:\n${r.path}\n\n${r.note}\n\nOpen the HOI4 launcher and enable ${project.modDisplayName||'the test mod'}`);status.textContent=r.error?'Install failed':'Test build installed'};
function validate(){const ids=new Set(),errors=[];for(const f of project.focuses){if(ids.has(f.id))errors.push('Duplicate focus ID: '+f.id);ids.add(f.id)}for(const f of project.focuses)for(const k of ['prerequisites','visualConnections','mutuallyExclusive'])for(const id of f[k]||[])if(!ids.has(id))errors.push(`${f.id} has a missing ${k} link to ${id}`);const dids=new Set();for(const d of project.decisions||[]){if(dids.has(d.id))errors.push('Duplicate decision ID: '+d.id);dids.add(d.id);if(d.linkedFocus&&!ids.has(d.linkedFocus))errors.push(`${d.id} links to missing focus ${d.linkedFocus}`)}const cids=new Set();for(const c of project.characters||[]){if(cids.has(c.id))errors.push('Duplicate character ID: '+c.id);cids.add(c.id);if(c.linkedFocus&&!ids.has(c.linkedFocus))errors.push(`${c.id} links to missing focus ${c.linkedFocus}`);if(c.linkedDecision&&!dids.has(c.linkedDecision))errors.push(`${c.id} links to missing decision ${c.linkedDecision}`)}
 const catalog=new Map((project.stateCatalog||[]).map(s=>[Number(s.id),s]));for(const f of project.focuses)for(const e of f.effects||[]){if(e.category!=='state')continue;if(e.mapProfile&&e.mapProfile!==project.mapProfile)errors.push(`${f.name||f.id}: state reward was made for ${profileLabel(e.mapProfile)}, but project uses ${profileLabel(project.mapProfile)}`);let s=catalog.get(Number(e.state));if(!s&&e.stateName){const wanted=String(e.stateName).trim().toLowerCase();const matches=[...catalog.values()].filter(x=>String(x.name).trim().toLowerCase()===wanted);if(matches.length===1){s=matches[0];e.state=s.id;e.population=s.population}}if(!s)errors.push(`${f.name||f.id}: state ${e.state} does not exist in ${profileLabel(project.mapProfile)}`);else if(e.province&&!s.provinces.includes(Number(e.province)))errors.push(`${f.name||f.id}: province ${e.province} is not inside ${s.name} on ${profileLabel(project.mapProfile)}`)}return errors}
$('#undo').onclick=()=>{if(!history.length)return;future.push(JSON.stringify(project));project=JSON.parse(history.pop());selected=null;selectedFocuses=new Set();changed('Undo');renderEditor();renderEvents();renderDecisions();renderCharacters();renderSpirits();renderSpiritEditor()};$('#redo').onclick=()=>{if(!future.length)return;history.push(JSON.stringify(project));project=JSON.parse(future.pop());selected=null;selectedFocuses=new Set();changed('Redo');renderEditor();renderEvents();renderDecisions();renderCharacters();renderSpirits();renderSpiritEditor()};
$$('header [data-tab]').forEach(b=>b.onclick=()=>{$$('header [data-tab]').forEach(x=>x.classList.toggle('active',x===b));$$('.tab').forEach(x=>x.classList.remove('active'));$('#'+b.dataset.tab+'Tab').classList.add('active');if(b.dataset.tab==='sources')renderSourceManager().then(enhanceSourceControls).catch(e=>showMessage(e.message||String(e)));if(b.dataset.tab==='tech')loadTechnologyTree().catch(e=>showMessage(e.message||String(e)))});

