function setModFiles(files){pendingModFiles=[...files];importButton.disabled=!pendingModFiles.length;importResult.textContent=pendingModFiles.length?`${pendingModFiles.length} files selected. Ready to recover the focus tree.`:'No folder selected.'}
async function filesFromEntry(entry,path=''){if(entry.isFile)return new Promise(resolve=>entry.file(file=>{file._importPath=path+file.name;resolve([file])}));if(!entry.isDirectory)return[];const reader=entry.createReader(),children=await new Promise(resolve=>{const all=[];const next=()=>reader.readEntries(batch=>{if(batch.length){all.push(...batch);next()}else resolve(all)});next()});return (await Promise.all(children.map(child=>filesFromEntry(child,path+entry.name+'/')))).flat()}
modDrop.onclick=()=>modInput.click();modInput.onchange=e=>setModFiles(e.target.files);modDrop.ondragover=e=>{e.preventDefault();modDrop.classList.add('dragging')};modDrop.ondragleave=()=>modDrop.classList.remove('dragging');modDrop.ondrop=async e=>{e.preventDefault();modDrop.classList.remove('dragging');const entries=[...e.dataTransfer.items].map(x=>x.webkitGetAsEntry?.()).filter(Boolean);setModFiles(entries.length?(await Promise.all(entries.map(x=>filesFromEntry(x)))).flat():e.dataTransfer.files)};
importButton.onclick=async()=>{if(!pendingModFiles.length)return;if(!confirm('Replace the open editor project with the focus tree from this mod folder? A backup will be created.'))return;importButton.disabled=true;importResult.textContent='Reading focus tree files…';try{const pathOf=f=>(f._importPath||f.webkitRelativePath||f.name).replaceAll('\\','/');const useful=pendingModFiles.filter(f=>{const p=pathOf(f).toLowerCase();return p.endsWith('hoi4_focus_studio_project.json')||p.includes('/common/national_focus/')||p.includes('/localisation/english/')||p.includes('/events/nho_editor_events.txt')||((p.includes('/interface/')||p.startsWith('interface/'))&&p.endsWith('.gfx'))});const imageFiles=pendingModFiles.filter(f=>{const p=pathOf(f).toLowerCase();return (p.includes('/gfx/interface/')||p.startsWith('gfx/interface/'))&&(p.endsWith('.dds')||p.endsWith('.png')||p.endsWith('.tga'))});const files={};for(const f of useful)files[pathOf(f)]=await f.text();const binaryFiles={};for(const f of imageFiles){binaryFiles[pathOf(f)]=await new Promise((resolve,reject)=>{const r=new FileReader();r.onload=()=>resolve(r.result);r.onerror=()=>reject(r.error);r.readAsDataURL(f)})}const result=await api('/api/import-mod',{files,binaryFiles});if(result.error)throw new Error(result.error);project=result.project;project.decisions??=[];project.characters??=[];project.nationalSpirits??=[];project.mapProfile=$('#mapProfile').value||'r56';for(const f of project.focuses){if(f.autoId===undefined)f.autoId=/^NHO_NOR_new_focus(?:_\d+)?$/.test(f.id);for(const e of f.effects||[])if(e.category==='state'&&!e.mapProfile)e.mapProfile=project.mapProfile;}await loadMapProfile(project.mapProfile,false);history=[];future=[];selected=null;selectedFocuses=new Set();render();renderEditor();renderEvents();renderDecisions();renderCharacters();renderSpirits();renderSpiritEditor();openTab('tree');status.textContent='Imported mod focus tree';importResult.textContent=`Imported ${project.focuses.length} focuses and ${project.events.length} events. ${result.mode}`;showMessage(importResult.textContent)}catch(error){importResult.textContent='Import failed: '+error.message;showMessage(importResult.textContent)}finally{importButton.disabled=false}};

